const Q_CHEMISTRY_2024_MODEL_I=[{"id": "objective>Chemistry>2024-Model-I>1", "question": "<div style=\"font-family:Cambria;font-size:17px;\">20 cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> of 0.09 mol dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> solution of tetraoxosulphate (VI) acid requires 30cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> of sodium hydroxide solution for complete neutralization. The molar concentration of sodium hydroxide is [H = 1; S = 32; 0 = 16; Na = 23]</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">0.03 mol dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> </div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.12 mol dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> </div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.27 mol dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> </div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.45 mol dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> </div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>SO4 + 2NaOH → Na<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span> + 2H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O <br/> 1 2 <br/> C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">A</span>V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">A</span>/C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">B</span>V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">B</span> = n<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">A</span>/n<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">B</span> <br/> C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">A</span>= 0.09 mol dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span>, V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">A</span> = 20cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span>, C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">B</span> = ? , V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">B</span> = 30cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span>,  n<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">A</span>=1, n<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">B</span>=2 <br/> 0.09*20/ C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">B</span> *30 = 1/2 <br/> make C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">B</span> the subject of the formula. <br/> C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">B</span> = 2*0.09*20/30  <br/> C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">B</span> = 0.12moldm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></div>", "topic": "ACID BASE AND SALTS : ACID AND BASE TITRATIONS"}, {"id": "objective>Chemistry>2024-Model-I>2", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which element contains the greatest number of moles?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">4 g of Helium</div>", "<div style=\"font-family:Cambria;font-size:17px;\">46 g of Carbon</div>", "<div style=\"font-family:Cambria;font-size:17px;\">78 g of Potassium</div>", "<div style=\"font-family:Cambria;font-size:17px;\">130g of Zinc</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Mole=reacting mass/molar mass. <br/> For helium:reacting mass=4.0g <br/> Molar mass=6g/mol <br/> Therefore mole=4/6=0.667mol <br/>  <br/> For carbon:reacting mass=46g <br/> Molar mass=12g/mol <br/> Therefore mole=46/12=3.833mol <br/>  <br/> For potassium : reacting mass=78g <br/> Molar mass=39.0g/mol <br/> Therefore mole=78/39=2mol <br/>  <br/> For zinc : reacting mass=130g <br/> Molar mass=65.0g/mol <br/> Therefore mole= 130/65=2mol <br/>  <br/> Carbon contains the greatest number of moles</div>", "topic": "CHEMICAL COMBINATION : THE MOLE CONCEPT AND AVOGADRO'S NUMBER"}, {"id": "objective>Chemistry>2024-Model-I>3", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In any chemical reaction, the total mass of products is always equal to that of the reactants. This Is statement of the law of</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">conservation of matter.</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Constant composition</div>", "<div style=\"font-family:Cambria;font-size:17px;\">definite proportions.</div>", "<div style=\"font-family:Cambria;font-size:17px;\">multiple proportions.</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The Law of Conservation of Matter, also known as the Law of Conservation of Mass, is a fundamental principle in science. It states that in any given system that is closed to the transfer of matter (in and out), the amount of matter in the system stays constant</div>", "topic": "CHEMICAL COMBINATION : LAWS OF CONSERVATION OF MATTER"}, {"id": "objective>Chemistry>2024-Model-I>4", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The alloy used for welding and plumbing contains</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">aluminum and copper</div>", "<div style=\"font-family:Cambria;font-size:17px;\">copper and tin</div>", "<div style=\"font-family:Cambria;font-size:17px;\">iron and aluminum</div>", "<div style=\"font-family:Cambria;font-size:17px;\">lead and tin</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The alloy used for welding and plumbing is called soft solder which contains- 50-70% Pb and 30-50% Sn.</div>", "topic": "METALS AND THEIR COMPOUNDS : ALLOY"}, {"id": "objective>Chemistry>2024-Model-I>5", "question": "<div style=\"font-family:Cambria;font-size:17px;\">On exposure to hydrogen sulphide, moist lead (II) ethanoate paper turns</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">black</div>", "<div style=\"font-family:Cambria;font-size:17px;\">blue</div>", "<div style=\"font-family:Cambria;font-size:17px;\">green</div>", "<div style=\"font-family:Cambria;font-size:17px;\">white</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">On exposure to hydrogen sulphide, moist lead (II) ethanoate paper turns black <br/> 1. This is due to the reaction of hydrogen sulphide with Pb²⁺ in the paper to form black lead (II) sulphide <br/> 2. The chemical reaction can be represented as follows: <br/> Pb<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2+</span>(aq)+H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>​S(g)→PbS(s)+2H<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">+</span>(aq) <br/> In this reaction, Pb²⁺ represents the lead (II) ions present in the moist lead (II) ethanoate paper, and H₂S represents the hydrogen sulphide gas. The product of the reaction is black lead (II) sulphide (PbS), which causes the color change2. This reaction is often used as a test for the presence of hydrogen sulphide</div>", "topic": "ENVIRONMENTAL POLLUTION : AIR POLLUTION~~NON-METALS AND THEIR COMPOUNDS : SULPHUR"}, {"id": "objective>Chemistry>2024-Model-I>6", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The maximum number of electrons that can occupy the shell having a principal quantum number of 3 is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">3</div>", "<div style=\"font-family:Cambria;font-size:17px;\">9</div>", "<div style=\"font-family:Cambria;font-size:17px;\">18</div>", "<div style=\"font-family:Cambria;font-size:17px;\">10</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">2n² <br/> Where n=3 <br/> 2(3)²=2×9=18 <br/> The maximum number of electrons that can occupy the shell having a principal quantum number of 3 is 18</div>", "topic": "ATOMIC STRUCTURE AND BONDING : THE PERIODIC TABLE AND PERIODICITY OF ELEMENTS"}, {"id": "objective>Chemistry>2024-Model-I>7", "question": "<div style=\"font-family:Cambria;font-size:17px;\">What is the ratio of the rate of diffusion of carbon(IV) oxide to that of propane, under the same conditions? [H = 1; C= 12; 0= 16]</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">1:1</div>", "<div style=\"font-family:Cambria;font-size:17px;\">4:1</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2:1</div>", "<div style=\"font-family:Cambria;font-size:17px;\">3:1</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The ratio of the rate of diffusion of gases can be calculated using Graham's Law, which states that the rate of diffusion or effusion of a gas is inversely proportional to the square root of its molar mass12. <br/>  <br/> First, let's calculate the molar masses of carbon(IV) oxide (CO2) and propane (C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">8</span>): <br/>  <br/> Molar mass of CO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> = 1C + 2O = 1(12) + 2(16) = 44 g/mol <br/> Molar mass of C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">8</span> = 3C + 8H = 3(12) + 8(1) = 44 g/mol <br/> According to Graham's Law, the ratio of the rate of diffusion of carbon(IV) oxide to that of propane is given by the square root of the inverse ratio of their molar masses2. Since the molar masses of both gases are equal, the ratio of their rates of diffusion will be 1:1. <br/>  <br/> So, the ratio of the rate of diffusion of carbon(IV) oxide to that of propane, under the same conditions, is 1:1</div>", "topic": "CHEMICAL COMBINATION : GAY LUSSAC'S LAW OF COMBINING VOLUMES~~GAS LAW"}, {"id": "objective>Chemistry>2024-Model-I>8", "question": "<div style=\"font-family:Cambria;font-size:17px;\">How much sodium hydroxide is required to make 250 cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> of 0.1 molar solution? [Na=23; 0=16; H=1]</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">10.0 g</div>", "<div style=\"font-family:Cambria;font-size:17px;\">4.0g</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2.0 g</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1.0g</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">no of moles of Na = molar concentration X   volume <br/> = 0.1 x 250/1000 <br/>  = 0.025 <br/> no of moles =  mass/Molar mass <br/> molar mass of NaOH = 40g/mol) <br/>  mass = no of moles x molar mass = 0.025 x 40 = 1.0g </div>", "topic": "CHEMICAL COMBINATION : THE MOLE CONCEPT AND AVOGADRO'S NUMBER"}, {"id": "objective>Chemistry>2024-Model-I>9", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The oxidation number of X in XO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span><span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3-</span> is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">1</div>", "<div style=\"font-family:Cambria;font-size:17px;\">-2</div>", "<div style=\"font-family:Cambria;font-size:17px;\">3</div>", "<div style=\"font-family:Cambria;font-size:17px;\">5</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The oxidation number of O  is 2- <br/> X + (-2 x 4) = -3 <br/> X - 8 = -3 <br/> X = -3+8 <br/> X = 5</div>", "topic": "OXIDATION AND REDUCTION : OXIDATION"}, {"id": "objective>Chemistry>2024-Model-I>10", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> The temperature at which the substance is melting is_____________the temperature at which the substance is freezing.</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">less than</div>", "<div style=\"font-family:Cambria;font-size:17px;\">more than </div>", "<div style=\"font-family:Cambria;font-size:17px;\">the same as</div>", "<div style=\"font-family:Cambria;font-size:17px;\">not the same as</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The temperature at which a substance melts is indeed the same temperature at which it freezes. This is known as the substance's melting point or freezing point. For example, water freezes and melts at 0°C (32°F) under standard pressure conditions.</div>", "topic": "KINETIC THEORY OF MATTER AND GAS LAWS : THE LAWS OF BOYLE, CHARLES, GRAHAM AND DALTON LAW OF PARTIAL PRESSURE"}, {"id": "objective>Chemistry>2024-Model-I>11", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is TRUE of a catalyst?  <br/> I. it alters the activation energy of a reaction <br/> II. it is effective in a reaction but cannot initiate a reaction <br/> III, it affects the equilibrium of a reversible reaction <br/> IV. it affects the overall reaction</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\"> I and II only</div>", "<div style=\"font-family:Cambria;font-size:17px;\">I, II and III only</div>", "<div style=\"font-family:Cambria;font-size:17px;\">II and III only</div>", "<div style=\"font-family:Cambria;font-size:17px;\">II, II and IV only</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"> I and II only are characteristics of a catalyst. I. it alters the activation energy of a reaction <br/> II. it is effective in a reaction but cannot initiate a reaction.</div>", "topic": "RATE OF CHEMICAL REACTION : FACTORS"}, {"id": "objective>Chemistry>2024-Model-I>12", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The Atomic theory model which explains that electrons in an atom revolve round quantized energy levels is attributed to</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Becquerel</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Bohr</div>", "<div style=\"font-family:Cambria;font-size:17px;\">de Broglie</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Rutherford</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The Atomic theory model that describes electrons revolving around quantized energy levels in an atom is attributed to Niels Bohr: This is known as the Bohr model. <br/> Bohr's Model: Electrons orbit the nucleus at fixed energy levels, known as quantized energy levels. <br/> Principal Quantum Number: Each orbit is denoted by a principal quantum number, which is a key concept in Bohr's atomic theory</div>", "topic": "ATOMIC STRUCTURE AND BONDING : THE CONCEPT OF ATOMS, MOLECULES AND IONS"}, {"id": "objective>Chemistry>2024-Model-I>13", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A compound that could be dried by using conc. tetraoxosulphate (VI) acid and not by calcium oxide is likely to be</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">an alkaline gas</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a neutral salt</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a deliquescent salt <br/> </div>", "<div style=\"font-family:Cambria;font-size:17px;\">an acid anhydride</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The compound that could be dried by using conc. tetraoxosulphate (VI) acid and not by calcium oxide is an acid anhydride. <br/> Acid anhydrides are compounds that can react with water to form acids. When acid anhydrides are exposed to air, they will absorb water from the air and become hydrated. This can make them difficult to dry with calcium oxide, which is a base.</div>", "topic": "ATOMIC STRUCTURE AND BONDING : ATOMIC STRUCTURE ELECTRON CONFIGURATION ATOMIC NUMBER MASS NUMBER AND ISOTOPES"}, {"id": "objective>Chemistry>2024-Model-I>14", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An atom of element X has an electronic configuration of 1s<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>2S<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>2p<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">6</span>3s<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>3p<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span>. In which group of the periodic table is X?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">2</div>", "<div style=\"font-family:Cambria;font-size:17px;\">3</div>", "<div style=\"font-family:Cambria;font-size:17px;\">4</div>", "<div style=\"font-family:Cambria;font-size:17px;\">5</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The electronic configuration given corresponds to the element phosphorus (P), which is in group 5 of the periodic table.</div>", "topic": "ATOMIC STRUCTURE AND BONDING : ATOMIC STRUCTURE ELECTRON CONFIGURATION ATOMIC NUMBER MASS NUMBER AND ISOTOPES"}, {"id": "objective>Chemistry>2024-Model-I>15", "question": "<div style=\"font-family:Cambria;font-size:17px;\">At s.t.p, a mole of chlorine occupies 22.4dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span>. If the temperature is changed to 35°C and the pressure to 750mHg the of the new volume will be </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">24.61dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">27.61dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">25.61dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">21.61dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">At S.T.P <br/> P1=760mmHg, T1=273k, V1=22.4dm³ <br/> P2=750mmHg, T2= (35°+273°)=308k <br/> V2 = ? <br/> (P1V1)/T1 = (P2V2)/T2 <br/> V2 = (P1V1T2)/P2T1 <br/> V2= 760 * 22.4 * 308/750 * 273 <br/> V2= 5243392/204750 <br/> V2 = 25.61dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></div>", "topic": "GAS LAW"}, {"id": "objective>Chemistry>2024-Model-I>16", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Tetraoxosulphate(VI) acid is not used for making carbon dioxide from calcium carbonate? This is because it </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">is a dehydrating agent</div>", "<div style=\"font-family:Cambria;font-size:17px;\">is a strong acid</div>", "<div style=\"font-family:Cambria;font-size:17px;\">is an oxidising agent</div>", "<div style=\"font-family:Cambria;font-size:17px;\">forms insoluble calcium tetraoxosulphate(Vl)</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The reason tetraoxosulphate(VI) acid is not used for making carbon dioxide from calcium carbonate is because it forms Insoluble Salt: It reacts with calcium carbonate to produce calcium tetraoxosulphate(VI), which is an insoluble salt.</div>", "topic": "NON-METALS AND THEIR COMPOUNDS : SULPHUR"}, {"id": "objective>Chemistry>2024-Model-I>17", "question": "<div style=\"font-family:Cambria;font-size:17px;\">What kind of bond exist between carbon and oxygen in C0<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span><span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2-</span>?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Co- ordinate Covalent</div>", "<div style=\"font-family:Cambria;font-size:17px;\">covalent</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Electrovalent</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Metallic</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The bonds between the carbon and oxygen atoms in the carbonate ion are covalent bonds. In a covalent bond, the atoms share electrons, allowing them to achieve a stable electron configuration. In the case of the carbonate ion, the carbon atom shares its electrons with the oxygen atoms, forming both single and double covalent bonds.</div>", "topic": "ATOMIC STRUCTURE AND BONDING : CHEMICAL BONDING"}, {"id": "objective>Chemistry>2024-Model-I>18", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A neon atom is chemically nonreactive because</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">the electrons at the outermost shell is partially filled</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the number of protons equals the number of electrons</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the outer electron shell is completely filled</div>", "<div style=\"font-family:Cambria;font-size:17px;\">there are equal number of protons and neutrons in its nucleus</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The atoms of noble gases already have complete outer shells, so they have no tendency to lose, gain, or share electrons. This is why the noble gases are inert and do not take part in chemical reactions.</div>", "topic": "ATOMIC STRUCTURE AND BONDING : ATOMIC STRUCTURE ELECTRON CONFIGURATION ATOMIC NUMBER MASS NUMBER AND ISOTOPES"}, {"id": "objective>Chemistry>2024-Model-I>19", "question": "<div style=\"font-family:Cambria;font-size:17px;\">When air is passed through alkaline pyrogallol and then lime water, the gases left are</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">nitrogen and carbon (IV) oxide</div>", "<div style=\"font-family:Cambria;font-size:17px;\">nitrogen and noble gases</div>", "<div style=\"font-family:Cambria;font-size:17px;\">nitrogen and oxygen</div>", "<div style=\"font-family:Cambria;font-size:17px;\">nitrogen, carbon (VI) oxide and noble gases</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">When air, which contains the gases oxygen, nitrogen, carbon dioxide, water vapor, and the rare gases, is passed through alkaline pyrogallol and then over quicklime, the gases left are nitrogen and the rare gases.</div>", "topic": "NON-METALS AND THEIR COMPOUNDS : NITROGEN"}, {"id": "objective>Chemistry>2024-Model-I>20", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> Which letter shows where noble gases are located on the Periodic Table?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">A</div>", "<div style=\"font-family:Cambria;font-size:17px;\">E</div>", "<div style=\"font-family:Cambria;font-size:17px;\">H</div>", "<div style=\"font-family:Cambria;font-size:17px;\">J</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Letter J represents the noble gases. Noble gases, also known as inert gases or aerogens, are the elements in group 18 of the periodic table. These gases are characterized by their low reactivity due to their full outer shell of valence electrons. Here are the noble gases: <br/>  <br/> Helium (He) <br/> Neon (Ne) <br/> Argon (Ar) <br/> Krypton (Kr) <br/> Xenon (Xe) <br/> Radon (Rn)</div>", "topic": "NON METALS:NOBLE GASES"}, {"id": "objective>Chemistry>2024-Model-I>21", "question": "<div style=\"font-family:Cambria;font-size:17px;\">How many zones are present in a luminous Bunsen burner flame?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">2</div>", "<div style=\"font-family:Cambria;font-size:17px;\">3</div>", "<div style=\"font-family:Cambria;font-size:17px;\">4</div>", "<div style=\"font-family:Cambria;font-size:17px;\">5</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The luminous bunsen burner flame has four zones namely: <br/>  <br/> Dark zone/ zone of unburnt gas; burning of the gas does not take place here, it is dark and cool. <br/> Luminous yellow zone; the gas burns in this zone but not completely because of limited air. Tiny particles glow in this region to give out light. <br/> Thin outer zone; the zone is colorless and gas burns completely due to plenty of air. <br/> Blue zone; this zone receives plenty of air and burning is more complete than in the luminous zone.</div>", "topic": "AIR : GASEOUS CONSTITUENTS"}, {"id": "objective>Chemistry>2024-Model-I>22", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following metals is NOT extracted by electrolysis?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Aluminium</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Calcium</div>", "<div style=\"font-family:Cambria;font-size:17px;\">iron</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Magnesium</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The metal among the options provided that is not typically extracted by electrolysis is iron. <br/> Aluminium, Calcium, Magnesium, and Sodium are typically extracted by electrolysis due to their high reactivity. Iron, on the other hand, is less reactive and is usually extracted from its ore (like hematite) using a method known as smelting, which involves heating the ore in a blast furnace</div>", "topic": "METALS AND THEIR COMPOUNDS : GENERAL CHARACTERISTICS AND PROPERTIES"}, {"id": "objective>Chemistry>2024-Model-I>23", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Catalytic hydrogenation of oils results in the production of</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">soaps</div>", "<div style=\"font-family:Cambria;font-size:17px;\">detergents</div>", "<div style=\"font-family:Cambria;font-size:17px;\">alkanes</div>", "<div style=\"font-family:Cambria;font-size:17px;\">margarine</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Catalytic hydrogenation of oils results in the production of saturated fats. This process is commonly used to convert unsaturated fats in vegetable oils into more stable saturated fats, a key step in the production of margarine.</div>", "topic": "ORGANIC COMPOUNDS : GIANT MOLECULES"}, {"id": "objective>Chemistry>2024-Model-I>24", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A sample of orange juice is suspected to have been contaminated with a yellow dye. Which of the following methods can be used to detect the dye?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Decantation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Chromatography</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Distillation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Filtration</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Chromatography is a separation technique that can be used to identify the components of a mixture. In this case, it can be used to separate the dye from the other components of the orange juice, allowing for its detection</div>", "topic": "SEPARATION OF MIXTURES AND PURIFICATION OF CHEMICAL : SEPARATION PROCESS"}, {"id": "objective>Chemistry>2024-Model-I>25", "question": "<div style=\"font-family:Cambria;font-size:17px;\">What is the temperature of propanone at 20 kPa? <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">40<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">20<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">15<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">55<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span></div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">From the graph, the temperature of propanone at 20 kPa is 15<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span>.</div>", "topic": "GAS LAW"}, {"id": "objective>Chemistry>2024-Model-I>26", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The electronic configuration 1s<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>2s<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>2p<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">6</span>3s<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>3p<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">6</span> is that of a</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">noble gas</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Group ll element</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Group lll element</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Group VI element</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The electronic configuration 1s²2s²2p⁶3s²3p⁶ corresponds to the element Argon (Ar). This configuration indicates that there are 18 electrons in the neutral state of this atom, which matches the atomic number of Argon. Argon is a noble gas, and its outer electron shell is fully occupied, making it very stable and unreactive</div>", "topic": "ATOMIC STRUCTURE AND BONDING : ATOMIC STRUCTURE ELECTRON CONFIGURATION ATOMIC NUMBER MASS NUMBER AND ISOTOPES"}, {"id": "objective>Chemistry>2024-Model-I>27", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The heat accompanying the reaction represented by the equation H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O (l) → H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O(g) is described as the heat of</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">solution</div>", "<div style=\"font-family:Cambria;font-size:17px;\">neutralization</div>", "<div style=\"font-family:Cambria;font-size:17px;\">vaporization</div>", "<div style=\"font-family:Cambria;font-size:17px;\">sublimation</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">It is described as the heat of vaporization. This term refers to the amount of heat energy required to transform a substance from a liquid state to a gaseous state at a constant temperature and pressure.</div>", "topic": "ENERGY CHANGES : ENDOTHERMIC AND EXOTHERMIC REACTIONS"}, {"id": "objective>Chemistry>2024-Model-I>28", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following reactions does not occur in the blast furnace during the extraction of iron?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Fe<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(s)</span> + 3CO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(g)</span> → 2Fe<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(l)</span> + 3CO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2(g)</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\"> CaO(s) + SiO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2(s)</span> → CaSiO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3(s)</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">s</span> + O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> → CO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2(g)</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">Fe<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">s</span> + 3Cl<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2(g)</span> → 2FeCl<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3(s)</span></div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Fe<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">s</span> + 3Cl<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2(g)</span> → 2FeCl<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3(s)</span> does not occur in the blast furnace during the extraction of iron</div>", "topic": "METALS AND THEIR COMPOUNDS : IRON"}, {"id": "objective>Chemistry>2024-Model-I>29", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A catayst which increases the rate of a chemical reaction does so by</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">increasing the surface area of the reactants</div>", "<div style=\"font-family:Cambria;font-size:17px;\">increasing the pressure on the system</div>", "<div style=\"font-family:Cambria;font-size:17px;\">decreasing the temperature at which the reaction occurs</div>", "<div style=\"font-family:Cambria;font-size:17px;\">decreasing the activation energy of the reaction</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A catalyst increases the rate of a chemical reaction by providing an alternative pathway for the reaction that has a lower activation energy. This lower activation energy means that a larger fraction of collisions are successful at a given temperature, leading to an increased reaction rate</div>", "topic": "RATE OF CHEMICAL REACTION : FACTORS"}, {"id": "objective>Chemistry>2024-Model-I>30", "question": "<div style=\"font-family:Cambria;font-size:17px;\">What evidence supports the claim that the diagram represents an alkyne? <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/></div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">The diagram has two carbon molecules.</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The diagram uses single bonds to attach functional groups</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The diagram has a triple bond between carbon molecules.</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The diagram shows the formula for a simple carbohydrate.</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">An alkyne is a hydrocarbon with one or more carbon-carbon triple covalent bonds. The simplest alkyne consists of two carbon atoms and is called ethyne</div>", "topic": "ORGANIC COMPOUNDS : ALIPHATIC HYDROCARBONS"}, {"id": "objective>Chemistry>2024-Model-I>31", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The gas that is liberated when iron is heated with concentrated tetraoxosulphate (VI)acid is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>S</div>", "<div style=\"font-family:Cambria;font-size:17px;\">SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">HCI</div>", "<div style=\"font-family:Cambria;font-size:17px;\">SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span></div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">When iron is heated with concentrated tetraoxosulphate (VI) acid, also known as sulfuric acid, the gas that is liberated is sulfur dioxide (SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>) <br/> Here's the chemical reaction: <br/>  <br/> Fe (s) + 2H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4(aq)</span> → FeSO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4(aq)</span> + SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2(g)</span> + 2H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(l)</span></div>", "topic": "NON-METALS AND THEIR COMPOUNDS : SULPHUR"}, {"id": "objective>Chemistry>2024-Model-I>32", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The compound of copper which is used in dyeing, disinfectant and as a fungicide is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">copper (ll) hydroxide</div>", "<div style=\"font-family:Cambria;font-size:17px;\">copper (ll) trioxonitrate (V) </div>", "<div style=\"font-family:Cambria;font-size:17px;\">copper (ll) tetraoxosulphate (VI)</div>", "<div style=\"font-family:Cambria;font-size:17px;\">copper (ll) oxide</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The compound of copper which is used in dyeing, disinfectant and as a fungicide is copper (II) tetraoxosulphate (VI). It's a versatile compound with a wide range of uses in various industries.</div>", "topic": "METALS AND THEIR COMPOUNDS : COPPER"}, {"id": "objective>Chemistry>2024-Model-I>33", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Nuclear reactions can be used in the following except</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">making atomic bombs</div>", "<div style=\"font-family:Cambria;font-size:17px;\">curing cancer</div>", "<div style=\"font-family:Cambria;font-size:17px;\">generating electricity</div>", "<div style=\"font-family:Cambria;font-size:17px;\">purifying water</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Nuclear reactions have a wide range of applications, including gauging the thickness of objects, making atomic bombs, curing cancer, and generating electricity. However, purifying water is typically not done using nuclear reactions. While radiation can be used to sterilize certain things, it's not commonly used to purify water.</div>", "topic": "NUCLEAR CHEMISTRY : NUCLEAR REACTIONS"}, {"id": "objective>Chemistry>2024-Model-I>34", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Thermal cracking of alkanes usually</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">involves decomposition</div>", "<div style=\"font-family:Cambria;font-size:17px;\">is an exothermic process </div>", "<div style=\"font-family:Cambria;font-size:17px;\">produces only small alkanes</div>", "<div style=\"font-family:Cambria;font-size:17px;\">requires hydrogen</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Thermal cracking is a process used in the petroleum industry to break down long-chain alkanes (hydrocarbons) into smaller, more useful hydrocarbons. It involves the decomposition of high-molecular-weight hydrocarbons, such as heavy crude oil fractions or long-chain alkanes, into lower-molecular-weight hydrocarbons, like smaller alkanes and alkenes. During thermal cracking, high temperatures and sometimes pressure are applied to the feedstock (such as crude oil or natural gas) to initiate the decomposition reactions.</div>", "topic": "ACID BASE AND SALTS : PH AND POH SCALE"}, {"id": "objective>Chemistry>2024-Model-I>35", "question": "<div style=\"font-family:Cambria;font-size:17px;\">What is the name of the compound shown? <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/></div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Benzene</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Methylpentene</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Toluene</div>", "<div style=\"font-family:Cambria;font-size:17px;\">propene</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Toluene is a naturally occurring compound derived primarily from petroleum or petrochemical processes. Toluene is a common component in gasoline, glues, and paint products. Toluene is a liquid, which is colourless, water-insoluble and smells like paint thinners. It is a mono-substituted colourless liquid, consisting of a CH3 group that is attached to a phenyl group. </div>", "topic": "ORGANIC COMPOUNDS : AROMATIC HYDROCARBONS"}, {"id": "objective>Chemistry>2024-Model-I>36", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The IUPAC names of the compounds CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>COOH and CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>=CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> are respectively;</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">ethanoic acid and ethene</div>", "<div style=\"font-family:Cambria;font-size:17px;\">ethanol and ethene</div>", "<div style=\"font-family:Cambria;font-size:17px;\">ethanol and ethyne</div>", "<div style=\"font-family:Cambria;font-size:17px;\">ethanoic acid and ethyne</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The IUPAC name of the compound CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>​COOH is Ethanoic Acid and the IUPAC name of the compound CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2​</span>=CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>​ is Ethene</div>", "topic": "ORGANIC COMPOUNDS : ALKANOIC ACIDS"}, {"id": "objective>Chemistry>2024-Model-I>37", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A gas jar was inverted over burning yellow phosphorus floating over water in a beaker. After burning, the water level was found to rise in the gas jar. The water level rises because</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">pressure inside the gas jar is greater than pressure outside it</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the air in the gas jar had been used up by burning</div>", "<div style=\"font-family:Cambria;font-size:17px;\">oxygen in the gas jar had been used up by burning</div>", "<div style=\"font-family:Cambria;font-size:17px;\">nitrogen in the gas jar had been used up by burning</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">This reaction consumes oxygen from the air inside the gas jar. As the oxygen is used up, the total number of gas molecules inside the jar decreases. This reduction in the number of gas molecules lowers the pressure inside the jar compared to the pressure outside the jar. <br/>  <br/> According to the principles of gas pressure, if the pressure inside the gas jar is lower than the pressure outside (atmospheric pressure), water will be pushed up into the jar to equalize the pressure. This is why the water level rises inside the gas jar after the phosphorus has finished burning.</div>", "topic": "GAS LAW"}, {"id": "objective>Chemistry>2024-Model-I>38", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In linear molecules, the bond angle is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">90<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">140<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">109<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">180<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span></div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In linear molecules, the bond angle is 180 degrees. The bond angle is the angle formed between three atoms across at least two bonds. For linear molecules, such as carbon dioxide (CO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>), the atoms are arranged in a straight line, hence the bond angle is 180 degrees.</div>", "topic": "ATOMIC STRUCTURE AND BONDING : SHAPES OF SIMPLE MOLECULES"}, {"id": "objective>Chemistry>2024-Model-I>39", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Separation of mixture of solids by physical methods can be based on differences in the following except</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">melting point</div>", "<div style=\"font-family:Cambria;font-size:17px;\">solubility</div>", "<div style=\"font-family:Cambria;font-size:17px;\">particle size</div>", "<div style=\"font-family:Cambria;font-size:17px;\">molar mass</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Separation of a mixture of solids by physical methods can be based on differences in melting point, solubility, and particle size. However, molar mass is not a physical property that can be used for the separation of a mixture of solids. Molar mass is a chemical property that refers to the mass of one mole of a substance.</div>", "topic": "SEPARATION OF MIXTURES AND PURIFICATION OF CHEMICAL : SEPARATION PROCESS"}, {"id": "objective>Chemistry>2024-Model-I>40", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The by-product of the fermentation of sugar to ethanol is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">propane -1,2,3-triol</div>", "<div style=\"font-family:Cambria;font-size:17px;\">ethyl ethanoate</div>", "<div style=\"font-family:Cambria;font-size:17px;\">ethanedioc acid</div>", "<div style=\"font-family:Cambria;font-size:17px;\">carbon (lV) oxide</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The by-product of the fermentation of sugar to ethanol is carbon (IV) oxide, also known as carbon dioxide. This is a common process in brewing and winemaking, where yeast ferments the sugars in the grapes or grains, producing ethanol and carbon dioxide.</div>", "topic": "ORGANIC CHEMISTRY: ALKANOL"}];
